    pathname: url.pathname,
    search: url.search,
    csrfToken: 'csrf-token',
    auth: {
      loginPath: '/auth/login',
      logoutPath: '/auth/logout',
    },
  });

  await bootstrapApp(targetWindow);
  await flush();

  return dom;
}

