import type { ArtifactSectionEnvelope } from '../../../shared/contracts/index.js';
import {
  appendSectionMessage,
  createSectionElement,
  renderSectionEnvelopeState,
} from './section-envelope.js';

export function renderArtifactSection(args: {
  envelope: ArtifactSectionEnvelope | null;
  targetDocument: Document;
}): HTMLElement {
  if (args.envelope === null || args.envelope.status !== 'ready') {
    return renderSectionEnvelopeState({
      title: 'Artifacts',
      envelope: args.envelope,
      targetDocument: args.targetDocument,
    });
  }

  const section = createSectionElement({
    title: 'Artifacts',
    targetDocument: args.targetDocument,
  });
  const list = args.targetDocument.createElement('ul');

  if (args.envelope.items.length === 0) {
    return appendSectionMessage({
      section,
      message: 'No artifacts yet.',
      targetDocument: args.targetDocument,
    });
  }

  for (const artifact of args.envelope.items) {
    const item = args.targetDocument.createElement('li');
    const heading = args.targetDocument.createElement('strong');
    const revision = args.targetDocument.createElement('p');
    const scope = args.targetDocument.createElement('p');
    const updatedAt = args.targetDocument.createElement('p');

    heading.textContent = artifact.displayName;
    revision.textContent =
      artifact.currentVersionLabel === null
        ? 'No current version available.'
        : `Current version: ${artifact.currentVersionLabel}`;
    scope.textContent =
      artifact.attachmentScope === 'project'
        ? 'Project-scoped artifact.'
        : `Attached to ${artifact.processDisplayLabel ?? artifact.processId ?? 'a process'}.`;
    updatedAt.textContent = `Updated: ${artifact.updatedAt}`;

    item.append(heading, revision, scope, updatedAt);
    list.append(item);
  }

  section.append(list);
  return section;
}

import type { CurrentProcessRequest } from '../../../shared/contracts/index.js';

function formatRequestKindLabel(kind: string): string {
  return kind.replaceAll('_', ' ');
}

export function renderCurrentRequestPanel(args: {
  currentRequest: CurrentProcessRequest | null;
  targetDocument: Document;
}): HTMLElement {
  const section = args.targetDocument.createElement('section');
  const title = args.targetDocument.createElement('h2');
  title.textContent = 'Current request';
  section.setAttribute('data-current-request-panel', 'true');
  section.setAttribute(
    'data-current-request-state',
    args.currentRequest === null ? 'none' : 'unresolved',
  );
  section.append(title);

  if (args.currentRequest === null) {
    const message = args.targetDocument.createElement('p');
    message.textContent = 'No unresolved request right now.';
    section.append(message);
    return section;
  }

  const attention = args.targetDocument.createElement('p');
  const kind = args.targetDocument.createElement('p');
  const prompt = args.targetDocument.createElement('p');
  const createdAt = args.targetDocument.createElement('p');
  attention.textContent = 'Attention required';
  kind.textContent = `Kind: ${formatRequestKindLabel(args.currentRequest.requestKind)}`;
  prompt.textContent = args.currentRequest.promptText;
  createdAt.textContent = `Requested: ${args.currentRequest.createdAt}`;
  section.append(attention, kind, prompt, createdAt);

  if (args.currentRequest.requiredActionLabel !== null) {
    const action = args.targetDocument.createElement('p');
    action.textContent = `Required action: ${args.currentRequest.requiredActionLabel}`;
    section.append(action);
  }

  return section;
}

import type { ProcessHistorySectionEnvelope } from '../../../shared/contracts/index.js';

function formatHistoryKindLabel(kind: string): string {
  if (kind === 'attention_request') {
    return 'Attention required';
  }

  return kind.replaceAll('_', ' ');
}

export function renderProcessHistorySection(args: {
  envelope: ProcessHistorySectionEnvelope | null;
  targetDocument: Document;
}): HTMLElement {
  const section = args.targetDocument.createElement('section');
  const title = args.targetDocument.createElement('h2');
  title.textContent = 'Process history';
  section.setAttribute('data-process-history-section', 'true');
  section.append(title);

  if (args.envelope === null) {
    const message = args.targetDocument.createElement('p');
    message.textContent = 'Loading process history...';
    section.append(message);
    return section;
  }

  if (args.envelope.status === 'empty') {
    const message = args.targetDocument.createElement('p');
    message.textContent = 'No visible process history yet.';
    section.append(message);
    return section;
  }

  if (args.envelope.status === 'error') {
    const message = args.targetDocument.createElement('p');
    message.textContent = args.envelope.error?.message ?? 'Process history failed to load.';
    section.append(message);
    return section;
  }

  const list = args.targetDocument.createElement('ol');

  for (const item of args.envelope.items) {
    const entry = args.targetDocument.createElement('li');
    const kind = args.targetDocument.createElement('strong');
    const body = args.targetDocument.createElement('p');
    const meta = args.targetDocument.createElement('p');

    entry.setAttribute('data-process-history-kind', item.kind);
    kind.textContent = formatHistoryKindLabel(item.kind);
    body.textContent = item.text;
    meta.textContent = `Created: ${item.createdAt}`;
    entry.append(kind, body, meta);
    list.append(entry);
  }

  section.append(list);
  return section;
}

